package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairAliasAwareInvocationTestSupport.*;

class ClonePair5319DifferenceFindingTest {

    private final ClonePair5319 subject = new ClonePair5319();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: no_termination.
     * Difference manifestation: the methods differ in whether they terminate.
     */
    @Test
    @BehavioralDifference(DifferenceType.NO_TERMINATION)
    void methodsHaveDifferentTimeoutBehaviorForGeneratedInput() {
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1(((Integer) values[0]).intValue()), 1000L, buildMethod1Inputs());
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2(((Integer) values[0]).intValue()), 1000L, buildMethod2Inputs());

        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(true)",
            null,
            "java.lang.Object[][Integer(2147483647)]",
            "java.lang.Object[][Integer(2147483647)]"
        );
        assertTextEquals("method1 status", "TIMEOUT", method1Outcome.status);
        assertTextEquals("originalInputsSnapshot", "java.lang.Object[][Integer(2147483647)]", method1Outcome.originalInputsSnapshot);
        assertDifferent(method1Outcome, method2Outcome);
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }

    private Object[] buildMethod1Inputs() {
        return new Object[]{Integer.MAX_VALUE};
    }

    private Object[] buildMethod2Inputs() {
        return new Object[]{Integer.MAX_VALUE};
    }
}
